mapper.select:
SELECT p.post_id AS postId, p.board_type AS boardType, p.category, p.title, p.user_num AS userNum, u.nickname AS authorName, p.view_cnt AS viewCnt, p.like_cnt AS likeCnt, p.created_at AS createdAt, (SELECT COUNT(*) FROM comments c WHERE c.post_id = p.post_id) AS commentCnt FROM post p JOIN users u ON p.user_num = u.user_num
AND p.board_type = #{boardType}
ORDER BY p.created_at DESC

mapper.update:
UPDATE post
SET view_cnt = view_cnt + 1
WHERE post_id = #{postId}
